{
  "action": "build_agent_system_configs",
  "section_identity": {
    "system_name": "agent_system",
    "system_slug": "agent_system",
    "route_prefix": "/create agents",
    "route_name": "agent_system_create_agents_command"
  },
  "section_agents": {
    "assistant_agent_name": "_xplaner_xrouter",
    "planner_agent_name": "_agent_system_planner",
    "worker_agent_name": "_agent_system_worker",
    "planner_prompt_name": "agent_system_planner",
    "worker_prompt_name": "agent_system_worker",
    "planner_model": "gpt-4o",
    "worker_model": "gpt-4o-mini",
    "agent_specs": [
      {
        "name": "planner",
        "agent_name": "_agent_system_planner",
        "role": "xplaner_xrouter",
        "responsibility": "Interactively clarify the requested agent system and prepare a structured build brief.",
        "tools": [
          "route_to_agent"
        ]
      },
      {
        "name": "worker",
        "agent_name": "_agent_system_worker",
        "role": "xworker",
        "responsibility": "Materialize persisted prompt, runtime, handoff, builder workflow, and route config bundles.",
        "tools": [
          "build_agent_system_configs",
          "@doc_rw"
        ]
      }
    ]
  },
  "section_workflows": {
    "planner_workflow_name": "agent_system_planner_router",
    "builder_workflow_name": "agent_system_builder_leaf",
    "workflow_specs": [
      {
        "name": "agent_system_planner_router",
        "kind": "router",
        "entry_state": "planner_ready",
        "owner_agent": "_agent_system_planner"
      },
      {
        "name": "agent_system_builder_leaf",
        "kind": "leaf",
        "entry_state": "builder_active",
        "owner_agent": "_agent_system_worker"
      }
    ]
  },
  "section_handoff_and_action": {
    "primary_to_planner_schema_name": "primary_to_agent_system_planner",
    "planner_to_builder_schema_name": "agent_system_planner_to_builder",
    "action_request_schema_name": "agent_system_builder_request",
    "action_tool_name": "build_agent_system_configs"
  },
  "section_planning": {
    "planning_schema": {
      "required_steps": [
        "capture_goal",
        "identify_agents",
        "define_workflows",
        "confirm_tools",
        "handoff_builder"
      ],
      "required_sections": [
        "agent_specs",
        "workflow_specs",
        "integration_targets"
      ],
      "required_agent_fields": [
        "name",
        "agent_name",
        "role",
        "responsibility",
        "tools"
      ],
      "required_workflow_fields": [
        "name",
        "kind",
        "entry_state",
        "owner_agent"
      ],
      "required_integration_fields": [
        "assistant_agent_name",
        "route_prefix",
        "persisted_config_target"
      ],
      "interactive": true,
      "builder_tool": "build_agent_system_configs"
    }
  },
  "section_integration": {
    "integration_targets": {
      "assistant_agent_name": "_xplaner_xrouter",
      "route_prefix": "/create agents",
      "persisted_config_target": "generated_agent_system_configs/agent_system_persisted_config.py"
    }
  },
  "section_execution": {
    "write_file": false,
    "persist_path": "generated_agent_system_configs/agent_system_persisted_config.py"
  }
}

